// src/lib/mocks/mockTripData.ts
import { Route } from '@/types/route';

export const mockRoutes: Route[] = [
  {
    id: '1',
    name: 'Gold Route',
    color: '#b3a369',
    delayMinutes: 2,
    stops: [
      { id: 'stop1', name: 'Tech Square WB', latitude: 33.777, longitude: -84.390, sequence: 1 },
      { id: 'stop2', name: '5th Street Bridge WB', latitude: 33.777, longitude: -84.392, sequence: 2 },
      { id: 'stop3', name: 'Klaus Building EB', latitude: 33.777, longitude: -84.396, sequence: 3 }
    ],
    busLocations: [],
    delayPredictions: [],
    active: true
  },
  {
    id: '2',
    name: 'Red Route',
    color: '#d11c1cff',
    delayMinutes: 3,
    stops: [
      { id: 'stop4', name: 'Klaus Building WB', latitude: 33.777, longitude: -84.396, sequence: 1 },
      { id: 'stop5', name: 'Nanotechnology', latitude: 33.778, longitude: -84.398, sequence: 2 },
      { id: 'stop6', name: 'Kendeda Building', latitude: 33.778, longitude: -84.400, sequence: 3 }
    ],
    busLocations: [],
    delayPredictions: [],
    active: true
  },
  {
    id: '3',
    name: 'Green Route',
    color: '#28a745',
    delayMinutes: 0,
    stops: [
      { id: 'stop7', name: '14th St & State St', latitude: 33.779, longitude: -84.395, sequence: 1 },
      { id: 'stop8', name: 'GTRI Conference Center', latitude: 33.780, longitude: -84.397, sequence: 2 },
      { id: 'stop9', name: 'McCamish & 10th St.', latitude: 33.781, longitude: -84.399, sequence: 3 }
    ],
    busLocations: [],
    delayPredictions: [],
    active: false
  }
];
